import{_ as d,V as t,W as s,X as e,Y as a,Z as o,$ as n,F as r}from"./framework-9e98e3f0.js";const l="/assets/memos-input-1e04fae3.png",c="/assets/memos-tag-filter-477f84f2.png",h="/assets/memos-quick-filter-a64b6985.png",u="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",g="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",p="/assets/memos-task-lists-9d7f982e.png",m="/assets/memos-settings-3579b7f8.png",b="/assets/memos-pomodoro-button-06b75b64.png",f="/assets/memos-pomodoro-break-f22b12f4.png",v="/assets/memos-pomodoro-stats-7abfc582.png",x="/assets/memos-pomodoro-settings-e37e4e45.png",A={},k=n('<h1 id="obsidian-闪念笔记插件-obsidian-memos" tabindex="-1"><a class="header-anchor" href="#obsidian-闪念笔记插件-obsidian-memos" aria-hidden="true">#</a> Obsidian 闪念笔记插件（obsidian-memos）</h1><p>像发微博一样记录灵感，支持时间戳、标签分类和历史浏览，类似 Flomo 的轻量笔记体验。闪念以列表项形式存储在 Journal 文件中，与 Logseq、日记流兼容。</p><h2 id="功能特点" tabindex="-1"><a class="header-anchor" href="#功能特点" aria-hidden="true">#</a> 功能特点</h2><ul><li><strong>快速捕获</strong>：快捷键即可记录灵感，无需中断工作流</li><li><strong>自动时间戳</strong>：每条闪念可自动添加 <code>HH:mm</code> 时间戳</li><li><strong>标签分类</strong>：支持 <code>#tag</code>，可按标签筛选</li><li><strong>任务支持</strong>：支持 Markdown 复选框（<code>- [ ]</code>）和关键词任务（<code>TODO</code>、<code>DOING</code>、<code>DONE</code>）</li><li><strong>时间追踪</strong>：点击任务复选框自动切换状态并追踪耗时（参考 obsidian-time-tracking）</li><li><strong>番茄钟</strong>：内置番茄工作法，与任务深度结合，支持专注/休息/统计（详见番茄钟章节）</li><li><strong>任务列表</strong>：特殊标签快速查看所有任务、待办任务、已完成任务</li><li><strong>快捷标签与聚合</strong>：配置常用标签按钮，支持多标签聚合（如 <code>cy+jf+qt+gw|每日记账</code>，点击后显示带任意一个标签的闪念）</li><li><strong>智能关键词</strong>：内容包含「数字 + 关键词」时自动加标签（如「午餐13」→ <code>#cy</code>），可与记账场景配合</li><li><strong>习惯打卡关键词</strong>：内容包含关键词即加标签（不需数字），适合打卡</li><li><strong>Journal 存储</strong>：闪念写在 <code>journals/YYYY-MM-DD.md</code>，与日记、记账同源</li><li><strong>外部写入自动刷新</strong>：监听 vault 与 metadataCache，Alfred、Python 等外部写入日记后视图会自动刷新</li></ul><h2 id="安装方法" tabindex="-1"><a class="header-anchor" href="#安装方法" aria-hidden="true">#</a> 安装方法</h2><h3 id="从-github-release-安装-推荐" tabindex="-1"><a class="header-anchor" href="#从-github-release-安装-推荐" aria-hidden="true">#</a> 从 GitHub Release 安装（推荐）</h3>',6),_={href:"https://github.com/fengshuzi/obsidian-memos/releases",target:"_blank",rel:"noopener noreferrer"},O=e("li",null,[a("下载 "),e("code",null,"main.js"),a("、"),e("code",null,"manifest.json"),a("、"),e("code",null,"styles.css")],-1),D=e("li",null,[a("在库中创建 "),e("code",null,".obsidian/plugins/obsidian-memos/")],-1),N=e("li",null,"将上述文件放入该目录",-1),E=e("li",null,"重启 Obsidian 或重新加载插件，在设置 → 第三方插件中启用「闪念笔记」",-1),j=n(`<h3 id="手动构建" tabindex="-1"><a class="header-anchor" href="#手动构建" aria-hidden="true">#</a> 手动构建</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> obsidian-memos
<span class="token function">npm</span> <span class="token function">install</span>
<span class="token function">npm</span> run build
<span class="token comment"># 将 dist/ 下文件复制到 .obsidian/plugins/obsidian-memos/</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始" aria-hidden="true">#</a> 快速开始</h2><h3 id="_1-确认-journal-目录" tabindex="-1"><a class="header-anchor" href="#_1-确认-journal-目录" aria-hidden="true">#</a> 1. 确认 Journal 目录</h3><p>在设置中配置「Journal 文件夹」，默认为 <code>journals</code>。闪念会写入该目录下按日期命名的 md 文件（如 <code>journals/2026-01-30.md</code>）。</p><h3 id="_2-记录闪念" tabindex="-1"><a class="header-anchor" href="#_2-记录闪念" aria-hidden="true">#</a> 2. 记录闪念</h3><ul><li><strong>快捷键</strong>：<code>Cmd/Ctrl + Shift + M</code> 打开闪念输入弹窗</li><li><strong>命令面板</strong>：搜索「闪念笔记: 新建闪念」或「闪念笔记: 打开闪念视图」</li><li>在弹窗内输入内容后： <ul><li><code>Cmd/Ctrl + Enter</code>：发送</li><li><code>Cmd/Ctrl + Shift + Enter</code>：发送并继续输入</li></ul></li></ul><figure><img src="`+l+'" alt="输入" tabindex="0" loading="lazy"><figcaption>输入</figcaption></figure><h3 id="_3-查看与筛选" tabindex="-1"><a class="header-anchor" href="#_3-查看与筛选" aria-hidden="true">#</a> 3. 查看与筛选</h3><ul><li>打开左侧「闪念笔记」视图，按时间倒序浏览</li><li>使用顶部标签下拉或快捷标签按钮筛选（如「每日记账」「四象限」）</li><li>支持搜索框：按内容或标签关键词过滤</li></ul><figure><img src="'+c+'" alt="快速筛选：按关键词与标签" tabindex="0" loading="lazy"><figcaption>快速筛选：按关键词与标签</figcaption></figure><figure><img src="'+h+`" alt="快速筛选：快捷标签与筛选结果" tabindex="0" loading="lazy"><figcaption>快速筛选：快捷标签与筛选结果</figcaption></figure><h2 id="闪念格式" tabindex="-1"><a class="header-anchor" href="#闪念格式" aria-hidden="true">#</a> 闪念格式</h2><p>闪念以「列表项」形式存储在当日 Journal 文件中。</p><h3 id="带时间戳-推荐" tabindex="-1"><a class="header-anchor" href="#带时间戳-推荐" aria-hidden="true">#</a> 带时间戳（推荐）</h3><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> 14:30 这是一条闪念
<span class="token list punctuation">-</span> 14:35 #想法 #灵感 记录一个点子
<span class="token list punctuation">-</span> 15:00 #jf 房租2366.85 闪念笔记 每日记账
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解析规则：<code>- HH:mm</code> 开头的一行会被识别为一条闪念，后面的 <code>#tag</code> 会被提取为标签，其余为内容。</p><h3 id="任务格式" tabindex="-1"><a class="header-anchor" href="#任务格式" aria-hidden="true">#</a> 任务格式</h3><p>插件支持多种任务格式，所有任务都会被识别为闪念并显示对应的状态：</p><h4 id="_1-markdown-复选框" tabindex="-1"><a class="header-anchor" href="#_1-markdown-复选框" aria-hidden="true">#</a> 1. Markdown 复选框</h4><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> [ ] 13:33 完成项目报告
<span class="token list punctuation">-</span> [x] 14:00 回复邮件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-关键词任务" tabindex="-1"><a class="header-anchor" href="#_2-关键词任务" aria-hidden="true">#</a> 2. 关键词任务</h4><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> TODO 15:00 待办事项
<span class="token list punctuation">-</span> DOING 15:30 正在进行
<span class="token list punctuation">-</span> DONE 16:00 已完成
<span class="token list punctuation">-</span> NOW 16:30 立即执行
<span class="token list punctuation">-</span> LATER 17:00 稍后处理
<span class="token list punctuation">-</span> WAITING 17:30 等待中
<span class="token list punctuation">-</span> CANCELLED 18:00 已取消
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-任务状态显示" tabindex="-1"><a class="header-anchor" href="#_3-任务状态显示" aria-hidden="true">#</a> 3. 任务状态显示</h4><p>在闪念视图中，任务会显示对应的状态：</p><ul><li><strong>复选框</strong>：<code>[ ]</code> 未完成、<code>[x]</code> 已完成</li><li><strong>状态标签</strong>：DOING、NOW、LATER、WAITING 会显示彩色标签</li><li><strong>彩色边框</strong>：不同状态有不同颜色的左侧边框标识</li></ul><figure><img src="`+u+`" alt="任务状态显示" tabindex="0" loading="lazy"><figcaption>任务状态显示</figcaption></figure><h3 id="无时间戳-仅标签行" tabindex="-1"><a class="header-anchor" href="#无时间戳-仅标签行" aria-hidden="true">#</a> 无时间戳（仅标签行）</h3><p>若一行以 <code>- #tag ...</code> 开头，且其中任意一个标签属于「快捷标签」配置中的<strong>任一组关键词</strong>，也会被识别为闪念（用于与记账、习惯等聚合标签配合）：</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> #jf 房租2366.85 生活缴费
<span class="token list punctuation">-</span> #cy 午餐13 韭黄炒蛋
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>例如配置了 <code>cy+jf+qt+gw|每日记账</code> 时，带 <code>#jf</code>、<code>#cy</code>、<code>#qt</code>、<code>#gw</code> 中任意一个的这类行都会被识别并出现在「每日记账」筛选项下。</p><h2 id="快捷标签与聚合标签" tabindex="-1"><a class="header-anchor" href="#快捷标签与聚合标签" aria-hidden="true">#</a> 快捷标签与聚合标签</h2><p>在设置 → 「快捷标签」中配置，格式为逗号分隔的若干项，每项格式如下：</p><ul><li><strong>单标签</strong>：<code>关键词</code> 或 <code>关键词|显示名</code><br> 例如：<code>工作</code>、<code>p1|重要且紧急</code></li><li><strong>多标签聚合</strong>：<code>关键词1+关键词2+关键词3|显示名</code><br> 点击该按钮时，会筛选出<strong>带有其中任意一个标签</strong>的闪念。</li></ul><p>示例配置：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>今天也要用心过生活,p1|重要且紧急,cy+jf+qt+gw|每日记账,工作,sp+reading|习惯打卡
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>cy+jf+qt+gw|每日记账</code>：点击「每日记账」时，显示带 <code>#cy</code>、<code>#jf</code>、<code>#qt</code>、<code>#gw</code> 任一的闪念（与记账插件关键词一致时，可统一在闪念里记流水，在记账插件里看统计）。</li></ul><h2 id="智能关键词-记账识别" tabindex="-1"><a class="header-anchor" href="#智能关键词-记账识别" aria-hidden="true">#</a> 智能关键词（记账识别）</h2><p>在设置中配置 JSON，格式为：<code>{&quot;标签&quot;: [&quot;关键词1&quot;, &quot;关键词2&quot;]}</code>。<br> 当闪念<strong>内容</strong>中包含「数字 + 任一关键词」时，会自动为该条闪念加上对应标签。</p><p>示例：<code>{&quot;cy&quot;: [&quot;午餐&quot;,&quot;早餐&quot;,&quot;咖啡&quot;], &quot;jf&quot;: [&quot;房租&quot;,&quot;水电&quot;]}</code><br> 输入「午餐13 韭黄炒蛋」保存后，会自动带上 <code>#cy</code>。</p><h2 id="习惯打卡关键词" tabindex="-1"><a class="header-anchor" href="#习惯打卡关键词" aria-hidden="true">#</a> 习惯打卡关键词</h2><p>同样为 JSON 配置，但<strong>不需要数字</strong>，内容里出现关键词即加对应标签，适合打卡类闪念（如「深蹲50个」→ <code>#sp</code>）。</p><h2 id="任务时间追踪" tabindex="-1"><a class="header-anchor" href="#任务时间追踪" aria-hidden="true">#</a> 任务时间追踪</h2><p>插件支持类似 obsidian-time-tracking 的任务时间追踪功能（默认开启，可在设置中关闭）。</p><h3 id="使用方法" tabindex="-1"><a class="header-anchor" href="#使用方法" aria-hidden="true">#</a> 使用方法</h3><ol><li><strong>点击复选框切换状态</strong>：在闪念视图中直接点击任务的复选框或状态标签</li><li><strong>自动记录时间</strong>：切换到 DOING 状态时自动记录开始时间</li><li><strong>自动计算耗时</strong>：完成任务时自动计算并显示耗时</li></ol><h3 id="状态切换流程" tabindex="-1"><a class="header-anchor" href="#状态切换流程" aria-hidden="true">#</a> 状态切换流程</h3><p><strong>Markdown 复选框：</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ ] → DOING → [x]（带时长）
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>关键词任务：</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>TODO → DOING → DONE（带时长）
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h3><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token title important"><span class="token punctuation">#</span> 原始任务</span>
<span class="token list punctuation">-</span> [ ] 13:33 完成报告

<span class="token title important"><span class="token punctuation">#</span> 点击复选框后变为 DOING（记录开始时间）</span>
<span class="token list punctuation">-</span> DOING 14:00 <span class="token comment">&lt;!-- ts:2024-02-09T14:00:00.000Z|source:checkbox --&gt;</span> 完成报告

<span class="token title important"><span class="token punctuation">#</span> 再次点击后变为已完成（显示耗时）</span>
<span class="token list punctuation">-</span> [x] 13:33 完成报告 25分钟
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="配置选项" tabindex="-1"><a class="header-anchor" href="#配置选项" aria-hidden="true">#</a> 配置选项</h3><ul><li><strong>启用任务时间追踪</strong>：开启/关闭时间追踪功能（默认：开启）</li><li><strong>自动追加时长</strong>：完成任务时是否显示耗时（默认：开启）</li></ul><p>关闭时间追踪后，复选框变为只读，不会切换状态和记录时间。</p><figure><img src="`+g+'" alt="时间追踪设置" tabindex="0" loading="lazy"><figcaption>时间追踪设置</figcaption></figure><h2 id="任务列表标签" tabindex="-1"><a class="header-anchor" href="#任务列表标签" aria-hidden="true">#</a> 任务列表标签</h2><p>插件提供三个特殊的任务列表标签，可以快速筛选和查看任务（默认开启，可在设置中关闭或自定义名称）。</p><h3 id="三个特殊标签" tabindex="-1"><a class="header-anchor" href="#三个特殊标签" aria-hidden="true">#</a> 三个特殊标签</h3><ol><li><p><strong>ALL TASKS</strong>：显示所有任务</p><ul><li>包括所有 Markdown 复选框（<code>[ ]</code>、<code>[x]</code>）</li><li>包括所有关键词任务（<code>TODO</code>、<code>DOING</code>、<code>DONE</code> 等）</li></ul></li><li><p><strong>TODO LIST</strong>：显示未完成任务</p><ul><li><code>[ ]</code> - 未选中的复选框</li><li><code>TODO</code> - 待办</li><li><code>DOING</code> - 进行中</li><li><code>NOW</code> - 立即执行</li><li><code>LATER</code> - 稍后处理</li><li><code>WAITING</code> - 等待中</li></ul></li><li><p><strong>DONE LIST</strong>：显示已完成任务</p><ul><li><code>[x]</code> - 选中的复选框</li><li><code>DONE</code> - 已完成</li><li><code>CANCELLED</code> - 已取消</li></ul></li></ol><h3 id="使用方法-1" tabindex="-1"><a class="header-anchor" href="#使用方法-1" aria-hidden="true">#</a> 使用方法</h3><p>在快捷标签区域点击对应的任务列表标签即可筛选：</p><figure><img src="'+p+'" alt="任务列表标签" tabindex="0" loading="lazy"><figcaption>任务列表标签</figcaption></figure><h3 id="配置选项-1" tabindex="-1"><a class="header-anchor" href="#配置选项-1" aria-hidden="true">#</a> 配置选项</h3><p>在设置中可以：</p><ul><li>开启/关闭任务列表标签功能</li><li>自定义三个标签的显示名称（支持中英文）</li></ul><p>例如可以改为：</p><ul><li><code>所有任务</code> / <code>ALL TASKS</code></li><li><code>待办清单</code> / <code>TODO LIST</code></li><li><code>完成清单</code> / <code>DONE LIST</code></li></ul><h2 id="设置选项摘要" tabindex="-1"><a class="header-anchor" href="#设置选项摘要" aria-hidden="true">#</a> 设置选项摘要</h2><table><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>Journal 文件夹</td><td>闪念存储目录，默认 <code>journals</code></td></tr><tr><td>日期格式</td><td>文件名日期，默认 <code>YYYY-MM-DD</code></td></tr><tr><td>时间格式</td><td>时间戳格式，默认 <code>HH:mm</code></td></tr><tr><td>快捷标签</td><td>按钮与聚合标签，见上文格式</td></tr><tr><td>智能关键词</td><td>数字+关键词 → 自动标签（记账）</td></tr><tr><td>习惯打卡关键词</td><td>关键词 → 自动标签（打卡）</td></tr><tr><td>每页显示数量</td><td>列表分页条数</td></tr><tr><td>提交后保持弹窗打开</td><td>方便连续记录</td></tr><tr><td>启动时打开闪念</td><td>是否默认打开闪念视图</td></tr><tr><td>启用任务时间追踪</td><td>点击任务时自动切换状态并追踪耗时</td></tr><tr><td>自动追加时长</td><td>完成任务时显示耗时</td></tr><tr><td>启用任务列表标签</td><td>显示 ALL TASKS、TODO LIST、DONE LIST</td></tr><tr><td>任务列表标签名称</td><td>自定义任务列表标签的显示名称</td></tr><tr><td>启用番茄钟</td><td>是否显示番茄钟功能</td></tr><tr><td>专注时长</td><td>每个番茄的专注时间（默认 25 分钟）</td></tr><tr><td>短休息时长</td><td>番茄后的短休息（默认 5 分钟）</td></tr><tr><td>长休息时长</td><td>多个番茄后的长休息（默认 15 分钟）</td></tr><tr><td>长休息间隔</td><td>每多少个番茄后长休息（默认 4 个）</td></tr><tr><td>完成提示音</td><td>番茄和休息完成时播放提示音</td></tr></tbody></table><figure><img src="'+m+'" alt="设置界面" tabindex="0" loading="lazy"><figcaption>设置界面</figcaption></figure><h2 id="番茄钟功能" tabindex="-1"><a class="header-anchor" href="#番茄钟功能" aria-hidden="true">#</a> 番茄钟功能</h2><p>插件内置番茄工作法（Pomodoro）功能，可以与任务深度结合，帮助你保持专注。</p><h3 id="核心功能" tabindex="-1"><a class="header-anchor" href="#核心功能" aria-hidden="true">#</a> 核心功能</h3><ul><li>🍅 <strong>专注计时</strong>：为每个任务启动独立的番茄钟</li><li>⏸ <strong>暂停/继续</strong>：支持中途暂停和恢复</li><li>☕ <strong>自动休息</strong>：番茄完成后自动进入休息阶段</li><li>🌿 <strong>长短休息</strong>：连续完成多个番茄后进入长休息</li><li>⏭ <strong>跳过休息</strong>：可随时跳过休息开始下一个番茄</li><li>🔔 <strong>提示音</strong>：番茄和休息完成时播放提示音</li></ul><h3 id="使用方法-2" tabindex="-1"><a class="header-anchor" href="#使用方法-2" aria-hidden="true">#</a> 使用方法</h3><h4 id="启动番茄钟" tabindex="-1"><a class="header-anchor" href="#启动番茄钟" aria-hidden="true">#</a> 启动番茄钟</h4><p>番茄钟与任务状态深度绑定，支持两种启动方式：</p><p><strong>方式一：自动启动（推荐）</strong></p><p>当任务从 TODO 状态变为 DOING 状态时，番茄钟会自动启动：</p><ol><li>点击任务的复选框，将 <code>[ ]</code> 变为 DOING 状态</li><li>番茄钟自动开始倒计时</li><li>专注完成后自动进入休息阶段</li></ol><p><strong>方式二：手动启动</strong></p><p>点击任务卡片上的「🍅 开始专注」按钮手动启动番茄钟。</p><figure><img src="'+b+'" alt="番茄钟按钮" tabindex="0" loading="lazy"><figcaption>番茄钟按钮</figcaption></figure><h4 id="番茄钟控制" tabindex="-1"><a class="header-anchor" href="#番茄钟控制" aria-hidden="true">#</a> 番茄钟控制</h4><ul><li><strong>暂停</strong>：点击暂停按钮 ⏸ 暂停当前番茄</li><li><strong>继续</strong>：点击继续按钮 ▶ 恢复计时</li><li><strong>停止</strong>：点击停止按钮 ⏹ 取消当前番茄（不记录）</li><li><strong>完成</strong>：任务完成（DOING → DONE）时自动完成番茄钟并记录</li></ul><h4 id="休息阶段" tabindex="-1"><a class="header-anchor" href="#休息阶段" aria-hidden="true">#</a> 休息阶段</h4><p>番茄完成后会自动进入休息阶段：</p><ul><li><strong>短休息</strong>：默认 5 分钟，每个番茄后</li><li><strong>长休息</strong>：默认 15 分钟，每 4 个番茄后</li><li>休息期间可以点击「跳过」立即开始下一个番茄</li></ul><figure><img src="'+f+'" alt="番茄钟休息" tabindex="0" loading="lazy"><figcaption>番茄钟休息</figcaption></figure><h3 id="统计面板" tabindex="-1"><a class="header-anchor" href="#统计面板" aria-hidden="true">#</a> 统计面板</h3><p>通过左侧边栏的「番茄钟统计」图标可以查看详细的番茄统计：</p><figure><img src="'+v+'" alt="番茄钟统计" tabindex="0" loading="lazy"><figcaption>番茄钟统计</figcaption></figure><h4 id="今日统计" tabindex="-1"><a class="header-anchor" href="#今日统计" aria-hidden="true">#</a> 今日统计</h4><ul><li>🍅 今日完成的番茄数</li><li>⏱ 今日专注时长（分钟）</li><li>☕ 今日休息次数</li><li>💤 今日休息时长（分钟）</li></ul><h4 id="总计统计" tabindex="-1"><a class="header-anchor" href="#总计统计" aria-hidden="true">#</a> 总计统计</h4><ul><li>🍅 累计完成的番茄数</li><li>⏱ 累计专注时长</li><li>📐 平均每个番茄时长</li><li>📋 总记录条数</li></ul><h4 id="历史记录" tabindex="-1"><a class="header-anchor" href="#历史记录" aria-hidden="true">#</a> 历史记录</h4><ul><li>查看所有番茄钟历史记录</li><li>支持按时间、关联任务、时长排序</li><li>支持筛选（全部/已完成）</li><li>支持批量删除和清空</li></ul><h3 id="配置选项-2" tabindex="-1"><a class="header-anchor" href="#配置选项-2" aria-hidden="true">#</a> 配置选项</h3><p>在设置 → 「🍅 番茄钟」中配置：</p><table><thead><tr><th>设置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>启用番茄钟</td><td>是否显示番茄钟功能</td><td>开启</td></tr><tr><td>专注时长</td><td>每个番茄的专注时间</td><td>25 分钟</td></tr><tr><td>短休息时长</td><td>番茄后的短休息</td><td>5 分钟</td></tr><tr><td>长休息时长</td><td>多个番茄后的长休息</td><td>15 分钟</td></tr><tr><td>长休息间隔</td><td>每多少个番茄后长休息</td><td>4 个</td></tr><tr><td>完成提示音</td><td>完成时播放提示音</td><td>开启</td></tr></tbody></table><figure><img src="'+x+`" alt="番茄钟设置" tabindex="0" loading="lazy"><figcaption>番茄钟设置</figcaption></figure><h3 id="状态流转" tabindex="-1"><a class="header-anchor" href="#状态流转" aria-hidden="true">#</a> 状态流转</h3><p>番茄钟的状态机：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>idle → running ⇄ paused → completed → short_break/long_break → idle
                              ↘ stop(cancel) → idle
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="与任务的关联" tabindex="-1"><a class="header-anchor" href="#与任务的关联" aria-hidden="true">#</a> 与任务的关联</h3><p>番茄钟与闪念任务深度绑定：</p><ul><li><strong>自动启动</strong>：任务从 TODO → DOING 时自动启动番茄钟</li><li><strong>自动完成</strong>：任务完成（DOING → DONE）时自动完成番茄钟并记录</li><li><strong>自动取消</strong>：任务取消（DOING → CANCELLED）时跳过休息或停止番茄钟</li><li>每个番茄钟关联到具体的闪念任务</li><li>不足 1 分钟的专注不计入番茄记录</li><li>重启 Obsidian 后，运行中的番茄钟会变为暂停状态</li></ul><h2 id="与记账插件配合" tabindex="-1"><a class="header-anchor" href="#与记账插件配合" aria-hidden="true">#</a> 与记账插件配合</h2><ul><li>闪念笔记与记账类插件可共用同一批 Journal 文件（如 <code>journals/</code>）。</li><li>在闪念里用 <code>#cy</code>、<code>#jf</code>、<code>#gw</code> 等写流水（如 <code>- 14:00 #jf 房租2366.85</code>），用「每日记账」聚合标签在闪念里查看；记账插件从同一文件中解析金额与分类做统计。</li><li>两边的关键词建议一致（如记账里用 <code>jf</code>=生活缴费，闪念里也用 <code>#jf</code>），这样一条记录既可当闪念浏览，也可被记账统计。</li></ul><h2 id="外部修改自动刷新" tabindex="-1"><a class="header-anchor" href="#外部修改自动刷新" aria-hidden="true">#</a> 外部修改自动刷新</h2><p>当 Journal 被 <strong>Alfred、Python 脚本、Quick Add</strong> 等外部工具修改时，插件通过「vault 事件 + metadataCache.changed」双监听，在检测到目标文件变更后自动刷新视图，无需定时轮询。详见插件 README 中的「插件开发参考：监听文件变化并自动刷新视图」。</p><h2 id="常见问题" tabindex="-1"><a class="header-anchor" href="#常见问题" aria-hidden="true">#</a> 常见问题</h2><p><strong>Q: 带 <code>#jf</code> 的记账行为什么在「每日记账」里看不到？</strong><br> A: 确保该行被识别为闪念：要么是 <code>- HH:mm #jf ...</code> 格式，要么是 <code>- #jf ...</code> 且 <code>jf</code> 属于某个快捷标签的<strong>整组关键词</strong>（如 <code>cy+jf+qt+gw|每日记账</code> 里的 <code>jf</code>）。若之前不显示，多为只匹配了聚合里的第一个关键词，已修复为按整组关键词识别。</p><p><strong>Q: 闪念存在哪个文件？</strong><br> A: 存在「Journal 文件夹」下、按「日期格式」命名的 md 文件中，例如 <code>journals/2026-01-30.md</code>。</p><p><strong>Q: 如何修改默认标签？</strong><br> A: 在设置 → 「默认标签」中填写，新建闪念时会自动带上这些标签。</p><p><strong>Q: 任务复选框点击后没有反应？</strong><br> A: 检查设置中「启用任务时间追踪」是否开启。关闭后复选框变为只读，不会切换状态。</p><p><strong>Q: 如何查看所有待办任务？</strong><br> A: 点击快捷标签区域的「TODO LIST」标签，会自动筛选出所有未完成的任务。</p><p><strong>Q: 任务时间追踪的数据存在哪里？</strong> A: 时间追踪数据以 HTML 注释的形式存储在任务行中（如 <code>&lt;!-- ts:2024-02-09T14:00:00.000Z|source:checkbox --&gt;</code>），不影响阅读，可以被其他工具忽略。</p><p><strong>Q: 番茄钟数据存储在哪里？</strong> A: 番茄钟数据存储在 Obsidian 的 <code>data.json</code> 中，不在 markdown 文件中，不会影响笔记内容。</p><p><strong>Q: 重启 Obsidian 后番茄钟会怎样？</strong> A: 运行中的番茄钟会变为暂停状态，需要手动继续；休息阶段的番茄钟会被丢弃。</p><p><strong>Q: 如何查看番茄钟统计？</strong> A: 点击左侧边栏的「番茄钟统计」图标，可以查看今日/总计统计和历史记录。</p><p><strong>Q: 番茄钟可以自定义时长吗？</strong> A: 可以，在设置中可以配置专注时长（1-60分钟）、短休息时长、长休息时长和长休息间隔。</p><h2 id="开发" tabindex="-1"><a class="header-anchor" href="#开发" aria-hidden="true">#</a> 开发</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span>
<span class="token function">npm</span> run dev      <span class="token comment"># 开发模式</span>
<span class="token function">npm</span> run build    <span class="token comment"># 构建</span>
<span class="token function">npm</span> run release  <span class="token comment"># 发布到 GitHub</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="许可证" tabindex="-1"><a class="header-anchor" href="#许可证" aria-hidden="true">#</a> 许可证</h2><p>MIT License</p>`,129);function I(T,w){const i=r("ExternalLinkIcon");return t(),s("div",null,[k,e("ol",null,[e("li",null,[a("前往仓库 "),e("a",_,[a("Releases"),o(i)]),a(" 下载最新版本")]),O,D,N,E]),j])}const q=d(A,[["render",I],["__file","obsidian-memos.html.vue"]]);export{q as default};
